(504, '', 'ข้อใดเป็นประเด็นสำคัญในการเชื่อมโยงบทบาทของโลจิสติกส์ให้มีความสมบูรณ์', '', 'กิจการต้องเตรียมความพร้อมด้านกิจกรรมโลจิสติกส์ภายใน', '', 'ส่งเสริมความร่วมมือเฉพาะด้านความสามารถในการผลิตขององค์กร', '', 'องค์ประกอบภายนอกจะไม่มีส่วนสำคัญของการเชื่อมโยงบทบาทโลจิสติกส์', '', 'มีการจัดการโลจิสติกส์ภายในองค์กรและภายนอกองค์กรที่มีมาตรฐานเดียวกัน', 4, 1, '30214'),
(505, '', 'ปัจจัยสำคัญที่ทำให้ระบบโซ่คุณค่าเกิดประสิทธิผลสูงสุดคือข้อใด', '', 'การใช้เทคโนโลยีสารสนเทศเป็นตัวเชื่อมโยงระบบให้สามารถจัดการข้อมูลได้อย่างถูกต้องแม่นยำ', '', 'การมีบุคลากรที่มีความรู้ความสามารถด้านเทคโนโลยี', '', 'พนักงานทุกคนให้ความร่วมมือในการดำเนินงาน  ', '', 'มีงบประมาณพร้อมที่จะดำเนินการ', 1, 1, '30214'),
(506, '', 'ควรเลือกใช้ระบบเทคโนโลยีสารสนเทศใดมาใช้ในการบริหารงานคลังสินค้า', '', 'ระบบ TMS', '', 'ระบบ EDI', '', 'ระบบ MRP', '', 'ระบบ WMS', 4, 1, '30214'),
(507, '', 'ระบบ TMS  เป็นเทคโนโลยีสารสนเทศที่นำมาใช้ในการบริหารงานด้านใด', '', 'การจัดการศุลกากร', '', 'การจัดการคลังสินค้า', '', 'การจัดการการขนส่ง', '', 'การจัดการภายในองค์กร', 3, 1, '30214'),
(508, '', 'ข้อใดเป็นระบบเทคโนโลยีสารสนเทศในอนาคตของระบบโลจิสติกส์', '', 'ระบบ GPS', '', 'ระบบ RFID', '', 'ระบบ SMS', '', 'ระบบ ERP', 2, 1, '30214'),
(509, '', 'ข้อใดเป็นแหล่งข้อมูลสำคัญในการจัดทำฐานข้อมูลสินค้าคงคลัง', '', 'ระบบ Barcode', '', 'เครื่องคอมพิวเตอร์', '', 'ใบเบิกสินค้า (Picking Slip)', '', 'ใบสั่งซื้อสินค้า (Purchase Order)', 1, 1, '30214'),
(510, '', 'ข้อใดเป็นการวิเคราะห์ข้อมูลเพื่อนำไปใช้ประโยชน์ในงานจัดซื้อ', '', 'การให้บริการลูกค้า  การเลือกแหล่งขาย', '', 'การพยากรณ์ยอดขาย  การเลือกแหล่งขาย', '', 'การให้บริการลูกค้า   ระดับปริมาณสินค้าคงคลัง ', '', 'การเลือกแหล่งขาย    ระดับปริมาณสินค้าคงคลัง', 4, 1, '30214'),
(511, '', 'ต้นทุนใดที่ไม่เปลี่ยนแปลงไปตามระดับของการดำเนินงานหรือปริมาณการผลิตในช่วงของการดำเนินงานระดับหนึ่ง', '', 'ต้นทุนส่วนเพิ่ม', '', 'ต้นทุนคงที่', '', 'ต้นทุนทางตรง', '', 'ต้นทุนผันแปร', 2, 1, '30214'),
(512, '', 'ข้อใดเป็นต้นทุนที่นำมาพิจารณาในตัวแบบการสั่งซื้อที่ประหยัดที่สุด (EOQ)', '', 'ต้นทุนในการสั่งซื้อ กับ ต้นทุนในการเก็บรักษา', '', 'ต้นทุนเงินทุนหมุนเวียน กับ ต้นทุนในการสั่งซื้อ', '', 'ต้นทุนป้องกันความเสี่ยง กับ ต้นทุนในการเก็บรักษา', '', 'ต้นทุนเงินทุนหมุนเวียน กับ ต้นทุนในการเก็บรักษา', 1, 1, '30214'),
(513, '', 'ข้อใดเป็นสมมติฐานที่ถูกต้องของตัวแบบปริมาณการสั่งซื้อที่ประหยัดที่สุด (EOQ)', '', 'เวลานำ (Lead Time) ในการสั่งซื้อไม่คงที่', '', 'ไม่มีสินค้าระหว่างทางและไม่มีสินค้าขาดสต็อก', '', 'ต้องมีการสั่งซื้อสินค้าในแต่ละครั้งไม่ต่ำกว่า 2 ชนิด', '', 'ราคาสินค้าที่สั่งซื้อจะเปลี่ยนแปลงตามปริมาณการสั่งซื้อ', 2, 1, '30214'),
(514, '', 'ปัจจัยที่มีอิทธิพลต่อต้นทุนคือข้อใด', '', 'บรรจุภัณฑ์', '', 'มูลค่าของสินค้า', '', 'น้ำหนักและขนาดของสินค้า', '', 'พื้นที่ที่ใช้ในการขนส่งสินค้า', 4, 1, '30214'),
(515, '', 'ข้อใดเป็นต้นทุนคงที่ของการขนส่งทั้งหมด', '', 'ค่าน้ำมันยานพาหนะ ค่าบริหารจัดการ', '', 'ค่าล่วงเวลาของพนักงาน ค่าเสื่อมราคา', '', 'ค่าเบี้ยประกันภัยยานพาหนะ ค่าเสื่อมราคา', '', 'ค่าน้ำมันหล่อลื่น ค่าบำรุงรักษา', 3, 1, '30214'),
(516, '', 'บริษัท พีพี โลจิสติกส์ จำกัด  ดำเนินการให้บริการด้านการกระจายสินค้า  พบว่า ในหนึ่งเดือน  มีต้นทุนด้านบุคลากร 120,000 บาท ด้านพื้นที่ 50,000 บาท และต้นทุนด้านเครื่องจักร อุปกรณ์ 80,000 บาท โดยคิดค่าบริการจากลูกค้าพาเลตละ 325 บาท ในการดำเนินงานมีต้นทุน 75 บาทต่อพาเลต ข้อใดคือมูลค่าการให้บริการที่เป็นจุดคุ้มทุน', '', '292,500  บาท', '', '308,750  บาท', '', '325,000 บาท', '', '357,500 บาท', 3, 1, '30214'),
(517, '', 'ข้อใดเป็นวิธีการตรวจรับและการนับสินค้าที่ถูกต้อง', '', 'รับสินค้า  ตรวจสอบใบส่งสินค้า   นำสินค้าเก็บเข้าคลังสินค้า   นับจำนวนสินค้า', '', 'ตรวจสอบใบส่งสินค้า   นับจำนวนสินค้า   รับสินค้า  นำสินค้าเก็บเข้าคลังสินค้า', '', 'ตรวจสอบใบส่งสินค้า  รับสินค้า   นับจำนวนสินค้า   นำสินค้าเก็บเข้าคลังสินค้า', '', 'นับสินค้า   ตรวจสอบใบส่งสินค้า   รับสินค้า   นำสินค้าเก็บเข้าคลังสินค้า', 2, 1, '30214'),
(518, '', 'ข้อใดเป็นหลักการเคลื่อนย้ายสินค้าในคลังสินค้า', '', 'เคลื่อนย้ายสินค้าให้เป็นไปตามประสบการณ์ของผู้ปฏิบัติ', '', 'มีการแก้ปัญหาเฉพาะหน้าในการปฏิบัติงาน', '', 'แปลงหน่วยสินค้าทุกครั้งก่อนการเคลื่อนย้าย', '', 'บริหารพื้นที่ให้เกิดประโยชน์มากที่สุด', 4, 1, '30214'),
(519, '', 'ขั้นตอนใดที่ไม่มีการปฏิบัติในคลังสินค้า ', '', 'การรับสินค้า (Receiving)  ', '', 'การเก็บสินค้า (Put-away)', '', 'การหยิบสินค้า (Order picking)', '', 'การคัดแยก และแปลงหน่วย (Selection and Letdown)', 4, 1, '30214'),
(520, '', 'อุปกรณ์เครื่องมือชนิดใดใช้ประโยชน์ในงานคลังสินค้ามากที่สุด ', '', 'พาเลต', '', 'เครื่องพิมพ์บาร์โค้ด', '', 'รถบรรทุกขนาดใหญ่', '', 'รถ Fork Lift  ขนาดเล็ก', 4, 1, '30214'),
(521, '', 'ข้อใดเป็นขนาดการผลิตที่ประหยัด (Economy of scale) ในอุตสาหกรรมการขนส่ง', '', 'นำเทคโนโลยีมาใช้กับการขนส่ง', '', 'เลือกเส้นทางที่หลากหลายในการขนส่ง', '', 'จัดหาสิ่งอำนวยความสะดวกมาสนับสนุนการขนส่ง', '', 'เลือกใช้ยานพาหนะมีขนาดที่เหมาะสม และมีจำนวนเที่ยววิ่งจำนวนมาก', 4, 1, '30214'),
(522, '', 'ข้อใดเป็นความแตกต่างระหว่างการบริการขนส่งสินค้า กับ การบริการขนส่งผู้โดยสาร', '', 'ผู้ใช้บริการ', '', 'เส้นทางในการขนส่ง', '', 'ปฏิกิริยาการตอบสนอง', '', 'สถานีที่ใช้ในการขนส่ง', 3, 1, '30214'),
(523, '', 'ลักษณะการขนส่งข้อใดทำให้สินค้ามีมูลค่าเพิ่มขึ้น  ', '', 'การนำสินค้ามาคัดแยก หรือแปลงหน่วย', '', 'การนำสินค้าไปยังสถานที่ที่มีความต้องการ', '', 'การทำให้สินค้าและบริการมีความแตกต่างกัน', '', 'การทำให้แหล่งผลิตเคลื่อนที่มาอยู่ใกล้กับผู้บริโภค', 2, 1, '30214'),
(524, '', 'ข้อใดเป็นหลักการรวมกลุ่มการขนส่งในกลุ่มเศรษฐกิจ', '', 'เพิ่มมาตรการทางการค้า และการขนส่งร่วมกัน', '', 'จัดเส้นทางการขนส่งและการนำเข้ากับประเทศคู่ค้า', '', 'ร่วมมือในการผลิตสินค้าและบริการ การจัดจำหน่าย การขนส่ง', '', 'ขจัดอุปสรรคทางการค้าและให้ปัจจัยการผลิตเคลื่อนย้ายอย่างเสรี', 4, 1, '30214'),
(525, '', 'การตัดสินใจเลือกชนิดของยานพาหนะ และอุปกรณ์ประกอบพาหนะขึ้นอยู่กับปัจจัยใดมากที่สุด', '', 'นโยบาย และแผนงานขององค์กร', '', 'จำนวนสินค้า  และสภาพดินฟ้าอากาศ ', '', 'ลักษณะของสินค้า  และระยะทางในการขนส่ง', '', 'เส้นทางในการจัดส่ง  ขนาด และน้ำหนักของสินค้า', 4, 1, '30214'),
(526, '', 'โรงงานเจบี  ผลิตน้ำผลไม้ มีแหล่งวัตถุดิบที่ใช้ในการผลิตอยู่ห่างจากตลาด 100 กิโลเมตร  อัตราค่าบริการตันละ 1 บาท ต่อระยะทาง 1 กิโลเมตร  เมื่อผลิตเป็นน้ำผลไม้น้ำหนักจะลดลงจาก 100 ตัน เหลือ 80 ตัน จากกรณีศึกษา โรงงานเจบี ควรตั้งโรงงานไว้ในตำแหน่งใด', '', 'ใกล้ตลาด', '', 'ใกล้แหล่งวัตถุดิบ', '', 'กึ่งกลางระหว่างตลาด และแหล่งวัตถุดิบ', '', 'ตั้งตามนโยบายของผู้บริหารและผู้มีส่วนเกี่ยวข้อง', 2, 1, '30214'),
(527, '', 'สินค้าเคลื่อนไหวเร็ว มักใช้การขนส่งในรูปแบบใด ', '', 'แบบต่อเนื่องหลายรูปแบบ', '', 'แบบพิจารณาตามขนาดของลูกค้า', '', 'แบบใช้ศูนย์กระจายสินค้าเป็นจุดผ่าน', '', 'แบบจากโรงงานไปให้ลูกค้าหลายราย', 3, 1, '30214'),
(528, '', 'ข้อใดเป็นวิธีการจัดซื้อที่เหมาะสมที่สุด', '', 'เลือกซื้อจากแหล่งขายที่ใกล้ที่สุด', '', 'เลือกซื้อตามดุลยพินิจของผู้บริหาร', '', 'เลือกซื้อจากแหล่งขายที่ให้ส่วนลดมากที่สุด', '', 'เลือกซื้อให้เหมาะสมตามสภาพความต้องการใช้', 4, 1, '30214'),
(529, '', 'ข้อใดเป็นกระบวนการเริ่มต้นของการจัดซื้อ', '', 'ศรีประทุมทำเอกสาร PR ส่งฝ่ายจัดซื้อ', '', 'ศรีประไพทำเอกสาร PO ส่งฝ่ายจัดซื้อ', '', 'ศรีประจันทร์ทำ INVOICE ส่งฝ่ายจัดซื้อ', '', 'ศรีประภาอยู่ฝ่ายจัดซื้อส่งใบ PR ไปยังฝ่ายต่าง ๆ', 1, 1, '30214'),
(530, '', 'เพื่อขจัดปัญหาการจัดซื้อฉุกเฉินหรือซื้อจำนวนไม่มาก  ธุรกิจควรกำหนดวิธีการจัดซื้ออย่างจึงเหมาะสม', '', 'กำหนดขั้นตอนเกี่ยวกับเอกสารในการจัดซื้อ ', '', 'คัดเลือกรายละเอียดและความต้องการของฝ่ายจัดซื้อ', '', 'วางแผนการจัดซื้ออย่างรัดกุม ทุกช่วงเวลาของการปฏิบัติงาน', '', 'กำหนดความต้องการและรายละเอียดคุณสมบัติของสินค้า', 3, 1, '30214'),
(531, '', 'สินค้าคงคลังประเภทใดที่คาดการณ์ว่าอาจขาดแคลนและมีราคาเพิ่มขึ้นในอนาคต', '', 'สินค้าที่เก็บไว้ตามฤดูกาล (Seasonal Stock)', '', 'สินค้าที่เก็บไว้เพื่อเก็งกำไร (Speculative Stock)', '', 'สินค้าระหว่างการขนส่ง (In-transit Inventories)', '', 'สินค้าเพิ่มเติมหรือสินค้าคงคลังปลอดภัย (Buffer or Safety Stock)', 2, 1, '30214'),
(532, '', 'เอกสารทางการค้าใดที่ผู้ซื้อนำไปใช้ติดต่อกับธนาคารเพื่อขอเปิด L/C  ', '', 'ใบเสนอราคา  (Proforma Invoice)', '', 'ใบตราส่งสินค้า (Bill of  Lading)', '', 'ใบรับรองแหล่งกำเนิดของสินค้า (Certificate of Origin)', '', 'ใบแสดงการบรรจุหีบห่อและใบแสดงรายการน้ำหนักสินค้า (Packing list)', 1, 1, '30214'),
(533, '', 'จุดเด่นที่สำคัญของระบบ E-CUSTOMS PAPERLESS คือข้อใด', '', 'การส่งข้อมูลผ่านระบบ Internet ได้โดยตรง', '', 'มีระบบฐานข้อมูลที่ช่วยให้การจัดทำเป็นไปอย่างรวดเร็ว', '', 'เป็นเทคโนโลยีที่ผู้ประกอบการนำเข้าและส่งออกสามารถดำเนินการได้ด้วยตนเอง', '', 'ลดการป้อนข้อมูลที่ซ้ำซ้อน สามารถติดต่อส่งข้อมูลตรงไปยังถึงกรมศุลกากรเพื่อขอรหัสผ่าน Gateway โดยไม่ต้', 4, 1, '30214'),
(534, '', 'ข้อตกลง FTA หรือเขตการค้าเสรี เป็นข้อตกลงในลักษณะใด', '', 'ความร่วมมือระหว่างผู้นำเข้าและส่งออกของประเทศที่ตกลงอยู่ในเขตการค้าเสรี', '', 'เป็นข้อตกลงการค้าที่เกิดขึ้นในกลุ่มของประเทศที่อยู่ในภูมิภาคเดียวกัน เช่น กลุ่มอาเซียน', '', 'เป็นข้อตกลงที่เกิดขึ้นแบบทวิภาคี หรือกลุ่มประเทศ (พหุภาคี) เพื่อร่วมมือกันขจัดอุปสรรคทางการค้าทั้งที', '', 'เป็นสนธิสัญญาความร่วมมือกันในกลุ่มของประเทศที่เป็นพันธมิตรกันในด้านใดด้านหนึ่งเพื่อขจัดข้อขัดแย้งด้า', 3, 1, '30214'),
(535, '', 'การเตรียมการส่งออกสินค้าแบบ Re-export คือข้อใด', '', 'การขออนุญาตเป็นผู้ผลิตเพื่อการส่งออก', '', 'การส่งออกสินค้าซ้ำ ๆ ไปยังประเทศใดประเทศหนึ่ง', '', 'การนำเข้าสินค้ามาจากต่างประเทศและส่งออกไปยังอีกประเทศหนึ่ง', '', 'การนำสินค้าเข้ามาทำการผลิต และจำหน่ายออกไปยังอีกประเทศหนึ่ง', 3, 1, '30214'),
