(575, '', 'ถ้าต้องการสร้างระบบการควบคุมมอเตอร์ จงพิจารณาว่าจะต้องใช้วงจรอะไร ในการนำมาควบคุมการหมุนของมอเตอร์เพื่อให้สามารถใช้งานได้', '', 'วงจร H-Bridge', '', 'วงจร Drive  Motor', '', 'วงจร Drive  MOSFET', '', 'วงจร Pulse Width  Modulation', 1, 1, '30128'),
(576, '', 'จงพิจารณาว่า ข้อใดคืออุปกรณ์ ตรวจจับสัญญาณแสง', '', 'Switch', '', 'LCD', '', 'LED', '', 'LDR', 4, 1, '30128'),
(577, '', 'อุปกรณ์ชนิดใดที่ใช้ตรวจจับการเปลี่ยนแปลงระดับเสียงให้เอาต์พุตเป็นแรงดันตามการเปลี่ยนแปลงของระดับเสียง', '', 'Microphone', '', 'Speaker', '', 'LDR', '', 'Sound system', 1, 1, '30128'),
(578, '', 'การเชื่อมต่อไมโครคอนโทรลเลอร์กับอุปกรณ์ที่เป็นสวิตช์ สิ่งที่ควรคำนึงถึงเพื่อไม่ให้เกิดการผิดพลาดของการอ่านค่าสัญญาณมากที่สุดคือ', '', 'กระแสไฟฟ้า', '', 'วงจรของสวิตช์', '', 'หน้าสัมผัส', '', 'การเกิดสัญญาณ Bounce', 4, 1, '30128'),
(579, '', 'ถ้าต้องการควบคุมอุปกรณ์ไฟฟ้า AC 220V. ในลักษณะเปิด-ปิด ต้องใช้อุปกรณ์อิเล็กทรอนิกส์ใดในการทำงาน โดยที่มีอายุการใช้งานยาวนานและสัญญาณรบกวนน้อย', '', 'Solid State Relay', '', 'Magnetic Relay ', '', 'Relay', '', 'SCR', 1, 1, '30128'),
(580, '', 'ถ้าต้องการควบคุมความสว่างหลอดไฟ AC 220V.  ต้องใช้อุปกรณ์อิเล็กทรอนิกส์ใดในการทำงาน', '', 'Magnetic Relay', '', 'Relay', '', 'SCR', '', 'Triac', 4, 1, '30128'),
(581, '', 'ถ้าต้องวัดอัตราการไหลของน้ำในท่อต้องใช้เซนเซอร์ใดต่อไปนี้', '', 'Infrared   Sensor', '', 'Hall Effect  Sensor', '', 'Flow Sensor', '', 'Temperature Sensor', 3, 1, '30128'),
(582, '', 'อุปกรณ์ใดออกแบบเพื่อการเชื่อมต่อควบคุมแบบไร้สาย', '', 'Arduino', '', 'Arm', '', 'PIC', '', 'NodeMcu ESP8266', 4, 1, '30128'),
(583, '', 'ข้อใดคือองค์ประกอบของระบบควบคุมอุปกรณ์ไฟฟ้า อิเล็กทรอนิกส์', '', 'GUI, Controller,โปรแกรม', '', 'Input,Controller,Output', '', 'มอเตอร์,คอมพิวเตอร์,ฮีทเตอร์', '', 'GUI,โปรแกรม,เซ็นเซอร์', 2, 1, '30128'),
(584, '', 'ในการแสดงลำดับขั้นการทำงานของโปรแกรมควรเขียนในรูปแบบใด', '', 'Circuit', '', 'Diagram', '', 'Flow chart', '', 'Block Diagram', 3, 1, '30128'),
(585, '', 'ข้อใดเป็นความสามารถของไมโครคอนโทรลเลอร์ในการควบคุมความเร็วมอเตอร์', '', 'UART', '', 'PWM', '', 'Interrupt', '', 'SPI', 2, 1, '30128'),
(586, '', 'การควบคุมอุปกรณ์ผ่านอินเตอร์เน็ต โปรโตคอลใดที่มีระบบรักษาความปลอดภัยของข้อมูล', '', 'HTTP', '', 'HTTPS', '', 'TCP/IP', '', 'UDP', 2, 1, '30128'),
(587, '', 'ข้อใดคือคุณสมบัติของผู้ตรวจสอบงานเชื่อมโลหะที่ถูกต้อง', '', 'มีความรู้ด้านแบบงานและข้อกำหนดต่างๆ', '', 'มีความซื่อสัตย์', '', 'ป้องกันปัญหาที่เกิดขึ้นต่อสังคม', '', 'หลีกเลี่ยงปัญหาที่เกี่ยวข้องกับผลประโยชน์', 1, 1, '30103'),
(588, '', 'ข้อใด เรียงลำดับขั้นตอนงานตรวจสอบงานเชื่อมโลหะที่ถูกต้อง	', '', 'ตรวจเครื่องมืออุปกรณ์', '', 'ตรวจก่อนการเชื่อม และตรวจขณะทำการเชื่อม  ', '', 'ตรวจวัสดุงานเชื่อม และตรวจเครื่องมืออุปกรณ์', '', 'ตรวจก่อนการเชื่อม  ตรวจขณะทำการเชื่อม และตรวจหลังการเชื่อม', 4, 1, '30103'),
(589, '', 'การเตรียมเครื่องมืออุปกรณ์ก่อนนำไปใช้ในงานตรวจสอบต้องปฏิบัติอย่างไรเป็นขั้นตอนแรก\r\n', '', 'นำเครื่องมือมาใช้งานทันที', '', 'ใช้งานเสร็จแล้วค่อยเก็บ', '', 'ตรวจเช็คเครื่องมืออุปกรณ์', '', 'ทำความสะอาดเครื่องมือ', 3, 1, '30103'),
(590, '', 'หน้าที่ของบุคลากรผู้ตรวจสอบงานเชื่อม  NDT ระดับที่ 1 ตรงกับข้อใด?', '', 'ตั้งปรับเครื่องมือด้วยตัวเอง ดำเนินการตรวจสอบ', '', 'ตั้งปรับเครื่องมือด้วยตัวเอง แยกประเภทการตรวจสอบและรายงานผล ', '', 'จัดเตรียมเอกสารการสอนตลอดจนรวบรวมและรายงานผลการตรวจสอบ  ', '', 'เลือกวิธีการตรวจสอบ ตั้งและปรับเทียบอุปกรณ์ อ่านและวิเคราะห์โดยยึดมาตรฐาน ', 2, 1, '30103'),
(591, '', 'ข้อใดไม่ใช่หน้าที่ความรับผิดชอบของผู้ตรวจสอบงานเชื่อมโลหะ\r\n', '', 'ตรวจสอบอุปกรณ์ที่ใช้งาน', '', 'ตรวจการเตรียมรอยต่อ', '', 'ตรวจภาพการประกอบงาน', '', 'การรับรองการใช้มาตรฐาน', 4, 1, '30103'),
(592, '', 'การที่ผู้ทำการตรวจสอบจะต้องทำความสะอาดเครื่องมือเพื่อจุดประสงค์ตามข้อใด ', '', 'เพื่อให้สะดวกในการใช้ ', '', 'เพื่อเพิ่มมูลค่าของข้อมูล', '', 'เพื่อรักษาคุณภาพของเครื่องมือ', '', 'เพื่อเป็นหน้าที่ของผู้ตรวจสอบ ', 3, 1, '30103'),
(593, '', 'ข้อบกพร่องแบบใดเป็นอันตรายต่อ แนวเชื่อมมากที่สุด', '', 'มีรอยร้าว', '', 'มีเม็ดสเป็คเตอร์', '', 'เกิดกัดแหว่งขอบ', '', 'ขนาดของแนวเชื่อม', 1, 1, '30103'),
(594, '', 'แนวเชื่อมที่ดีควรมีลักษณะอย่างไร ', '', 'เต็มแนว', '', 'สวยงาม', '', 'ล้นแนว', '', 'ขอบแหว่ง', 1, 1, '30103'),
(595, '', 'การปฏิบัติงานตรวจสอบเสร็จแล้ว สิ่งที่ผู้ตรวจสอบส่งตรงเวลาที่กำหนด ข้อใดถูกต้องที่สุด\r\n', '', 'ใบบันทึกการตรวจสอบงานเชื่อม', '', 'ชิ้นงานเชื่อมต่อชนบากหน้างานท่าราบ', '', 'ชิ้นงานตรวจสอบการเชื่อมต่อชนบากหน้างานท่าขนานนอน', '', 'ใบบันทึกการตรวจสอบงานเชื่อมแบบไม่ทำลายสภาพด้วยสายตา', 4, 1, '30103'),
(596, '', 'การส่งผลการตรวจด้วยสายตาผู้ปฏิบัติงานควรกระทำเมื่อใด', '', 'ส่งก่อนเวลาที่กำหนด', '', 'ส่งเมื่อมีผู้ส่งตรวจสอบ', '', 'ส่งเมื่อเสร็จการตรวจสอบ', '', 'ส่งเมื่ออาจารย์ผู้สอนกำหนด', 3, 1, '30103'),
(597, '', 'ข้อใด ต้องทำก่อนลงมือตรวจสอบงานเชื่อมแบบไม่ทำลายสภาพด้วยน้ำยาแทรกซึม', '', 'ต้องเข้าใจการสรุปผลการตรวจสอบ', '', 'ต้องเข้าใจขั้นตอนการตรวจสอบชัดเจน', '', 'ต้องเข้าใจงานตรวจสอบทุกๆงานอย่างชัดเจน', '', 'ต้องเข้าใจวัตถุประสงค์การตรวจสอบอย่างชัดเจน', 4, 1, '30103'),
(598, '', 'สิ่งที่ไม่ต้องจัดเตรียมในงานตรวจสอบด้วยน้ำยาแทรกซึม(PT)', '', 'เกจวัดขนาดแนวเชื่อม', '', 'อุปกรณ์ทำความสะอาดชิ้น', '', 'หลอดไฟฟ้าฟลูออเรสเซนต์', '', 'แว่นขยายและน้ำยาทำความสะอาด', 1, 1, '30103'),
(599, '', 'ถ้าทำความสะอาดพื้นผิวชิ้นงานในการตรวจสอบด้วยน้ำยาแทรกซึม(PT)ไม่ดีจะมีผลกระทบอย่างไร\r\n\r\n', '', 'มองไม่เห็นข้อบกพร่อง', '', 'เกิดรอยแตกของน้ำยาตรวจสอบ', '', 'ไม่สามารถกำหนดตำแหน่งในการตรวจสอบได้', '', 'เป็นการเตรียมชิ้นทดสอบผิดจากมาตรฐานกำหนด', 1, 1, '30103'),
(600, '', 'ข้อใด เป็นงานตรวจสอบ ด้วยน้ำยาแทรกซึม(PT)ที่ถูกต้องและปลอดภัย\r\n', '', 'ทำการตรวจสอบแทรกซึม(PT)ในห้องที่มิดชิด', '', 'แสงในการตรวจสอบด้วยน้ำยาแทรกซึมสามารถมองด้วยตาเปล่าได้', '', 'การตรวจสอบแทรกซึม(PT)ไม่มีสารพิษที่เป็นอันตรายต่อร่างกาย', '', 'ก่อนทิ้งกระป๋องน้ำยาตรวจสอบแทรกซึม(PT)จะต้องเจาะรูที่กระป๋องเสียก่อน', 4, 1, '30103'),
(601, '', 'การกำจัดน้ำยาแทรกซึมส่วนเกินออกควรทำอย่างไร', '', 'ล้างออกด้วยน้ำและใช้ผ้าขาวเช็ดให้แห้ง', '', 'ล้างด้วยน้ำยาล้างจานเช็ดออกและเป่าให้แห้ง', '', 'ใช้น้ำยาทำความสะอาดฉีดลงบนชิ้นงานแล้วใช้ผ้าเช็ด', '', 'ฉีดน้ำยาใส่ผ้าขาวพอหมาดแล้วเช็ดออกจนกว่าไม่มีสีแดงติดผ้า', 4, 1, '30103'),
(602, '', 'การเตรียมผิวงานก่อนการตรวจสอบมีความสำคัญอย่างไร', '', 'ทำให้ไม่สิ้นเปลืองวัสดุ', '', 'ทำให้ช่วยป้องกันการกัดกร่อน', '', 'ทำให้มองเห็นสิ่งสกปรกได้ง่าย', '', 'ทำให้การตรวจสอบด้วยน้ำยาแทรกซึม(PT)ได้ผลดี', 4, 1, '30103'),
(603, '', 'Developing agent มีหน้าที่ทำอะไร', '', 'ทำหน้าที่ดูดซึมของของเหลว ', '', 'ทำหน้าที่ช่วยขยายรูปรอยบกพร่องให้เห็นได้ชัดขึ้น', '', 'ทำหน้าที่ดูดซับสารละลายที่แทรกซึมอยู่บริเวณรอยบกพร่อง', '', 'ทำหน้าที่ขจัดสารละลายส่วนเกินที่อยู่บนผิวหน้าชิ้นงานให้', 3, 1, '30103'),
(604, '', 'ข้อบกพร่องที่บ่งชี้ในการตรวจสอบด้วยน้ำยาแทรกซึม(PT)มีลักษณะอย่างไร', '', 'สิ่งบ่งชี้ลักษณะเป็นก้อน', '', 'สิ่งบ่งชี้ลักษณะเป็นของแข็ง', '', 'สิ่งบ่งชี้ลักษณะรูปร่างยาว', '', 'สิ่งบ่งชี้ลักษณะบ่งชี้รูปร่างกลมและรูปร่างยาว', 4, 1, '30103'),
(605, '', 'ข้อใด เป็นหลักเกณฑ์การบันทึกผลการตรวจสอบที่ผู้ตรวจสอบใช้ในการพิจารณาทบทวน \r\n', '', 'ผู้ตรวจสอบเป็นผู้พิจารณาอย่างครบถ้วน', '', 'ผู้ตรวจสอบที่เป็นหมอในการพิจารณาทบทวน', '', 'ผู้ตรวจสอบที่มีอำนาจเต็มในการพิจารณาทบทวน', '', 'ผู้ตรวจสอบที่เป็นตำรวจในการพิจารณาทบทวน', 3, 1, '30103'),
(606, '', 'ในรายงานบันทึกผลการตรวจสอบด้วยน้ำยาแทรกซึม(PT) หัวข้อแรกที่ต้องระบุในรายงานคือ\r\n', '', 'วัสดุชิ้นงานตรวจสอบ', '', 'ลำดับขั้นการตรวจสอบ', '', 'วัตถุประสงค์ของการตรวจสอบ', '', 'เครื่องมือและอุปกรณ์ที่กำหนดในการตรวจสอบ', 4, 1, '30103'),
(607, '', 'วัสดุชนิดใดไม่เหมาะ แก่การตรวจสอบด้วยอนุภาคแม่เหล็ก', '', 'เหล็กหล่อ', '', 'เหล็กกล้าชุบแข็ง', '', 'เหล็กกล้าตีขึ้นรูป', '', 'เหล็กกล้าสแตนเลสออสเทเนทิก', 4, 1, '30103'),
(608, '', 'ชิ้นงานชนิดใด ที่ไม่ควรนำมาตรวจสอบด้วยผงแม่เหล็ก(MT)', '', 'ชิ้นงานที่เป็นโลหะ', '', 'ชิ้นงานที่ซุปผิวด้วยโครเมี่ยม', '', 'ชิ้นงานที่มีข้อบกพร่องบนผิวรอยเชื่อม', '', 'ชิ้นงานที่ลอกสีออกและขัดทำความสะอาดแล้ว', 2, 1, '30103'),
(609, '', 'เครื่องมือใด ใช้ทดสอบความเพียงพอของกระแสไฟฟ้าที่เหนี่ยวนำให้เกิดแม่เหล็กแบบวงกลม\r\n', '', 'โยค(Yoke)', '', 'ขดลวดตัวนำ', '', 'พร์อด(Prods)', '', 'เกาส์มิเตอร์(Gauss Meter).', 4, 1, '30103'),
(610, '', 'ลักษณะชิ้นงานตรวจสอบแบบใด ที่ควรเลือกใช้ผงเหล็กชนิดเปียก  ', '', 'รอยสแล็กฝังลึก', '', 'รอยเชื่อมไม่เต็มร่องบาก', '', 'รอยซึมลึกไม่สมบูรณ์ที่แนวราก', '', 'รอยร้าวที่เกิดใต้ผิวงานเชื่อมโลหะ', 4, 1, '30103'),
(611, '', 'ข้อใด เป็นสิ่งสำคัญที่แตกต่างที่ผู้ตรวจสอบต้องทำเมื่อต้องตรวจสอบชิ้นงานด้วยผงแม่เหล็ก(MT)', '', 'กำหนดจุดตรวจ', '', 'กำหนดความนาของชิ้นงาน', '', 'ทำชิ้นทดสอบให้เป็นสนามแม่เหล็ก', '', 'ทำสัญญาว่าจ้างกับบริษัทที่มีความน่าเชื่อถือ', 3, 1, '30103'),
(612, '', 'ข้อใด เป็นการเตรียมผิวและทำความสะอาดผิวหน้าชิ้นงานด้วยผงแม่เหล็ก(MT)ได้ถูกต้อง', '', 'ขัดผิวหน้าชิ้นงานให้เรียบ', '', 'ตกแต่งเจียระไนชิ้นงานให้สะอาด ', '', 'ทำความสะอาดและเลือกใช้ผงแม่เหล็กชนิดเปียก', '', 'ทำความสะอาดบริเวณตรวจสอบเผื่อออกไปอีกข้างละไม่ต่ำกว่า 1 นิ้ว', 4, 1, '30103'),
(613, '', 'ลักษณะความบกพร่องรอยบ่งชี้ใด ที่ควรตรวจสอบด้วยผงแม่เหล็ก(MT)', '', 'ความบกพร่องโลหะงานเชื่อม', '', 'ความบกพร่องภายในแนวเชื่อม', '', 'ความบกพร่องที่แนวเชื่อมภายนอก', '', 'ความบกพร่องภายในและผิวนอกแนวเชื่อม', 4, 1, '30103'),
(614, '', 'เมื่อผู้ตรวจสอบทำการตรวจสอบด้วยผงแม่เหล็ก(MT)พบข้อบกพร่องบนชิ้นงานขั้นตอนต่อไปควรทำอย่างไร', '', 'เปลี่ยนผู้ทำงานตรวจสอบใหม่', '', 'นำชิ้นงานไปทดสอบด้วยการทำลาย', '', 'นำชิ้นงานไปตรวจสอบด้วยสายตา(VT)', '', 'นำชิ้นงานไปแก้ไขให้มีคุณภาพแล้วนำกลับมาตรวจสอบใหม่', 4, 1, '30103'),
(615, '', 'การตรวจสอบข้อบกพร่องด้วยผงแม่เหล็ก(MT)มีวิธีบันทึกผลอย่างไร', '', 'ถ่ายรูปข้อบกพร่อง', '', 'สเกตภาพข้อบกพร่อง', '', 'ใช้เทปใสแปะลอกข้อบกพร่อง', '', 'ใช้กระดาษกาวลอกข้อบกพร่อง', 1, 1, '30103');
INSERT INTO `tb_test` (`id`, `q_pic`, `q_t`, `c1_pic`, `c1`, `c2_pic`, `c2`, `c3_pic`, `c3`, `c4_pic`, `c4`, `answer`, `idgroup`, `subject`) VALUES
(616, '', 'ในรายงานบันทึกผลการตรวจสอบด้วยผงแม่เหล็ก(MT) หัวข้อแรกที่ต้องระบุในรายงานคือ', '', 'วัสดุชิ้นงานตรวจสอบ', '', 'ลำดับขั้นการตรวจสอบ', '', 'วัตถุประสงค์ของการตรวจสอบ', '', 'เครื่องมือและอุปกรณ์การตรวจสอบ', 4, 1, '30103'),
(617, '', 'ข้อใดคือวัตถุประสงค์ของการตรวจสอบด้วยคลื่นอัลตราโซนิก', '', 'การตรวจสอบหาข้อบกพร่องบนพื้นผิว', '', 'การตรวจสอบหารอยแตกร้าว ', '', 'การตรวจสอบหาข้อบกพร่องในเนื้อเชื่อม', '', 'การตรวจสอบหาข้อบกพร่องพื้นผิวและใต้พื้นผิว', 4, 1, '30103'),
(618, '', 'การตรวจสอบด้วยอำนาจแม่เหล็กแตกต่างกับการตรวจสอบด้วยคลื่นอัลตราโซนิกอย่างไร', '', 'ใช้ไฟฟ้าเป็นตัวหลัก AC/DC', '', 'ใช้น้ำยา/กระแสไฟฟ้า', '', 'ใช้คลื่นเสียง/คลื่นแม่เหล็ก', '', 'สารชนิดแห้ง/ชนิดเปียก', 3, 1, '30103'),
(619, '', 'ข้อใดไม่ใช่ส่วนประกอบสำคัญของการตรวจสอบด้วยคลื่นอัลตราโซนิค', '', 'ตัวกำเนิดคลื่นเสียง ', '', 'อุปกรณ์ขยายสัญญาณคลื่นเสียง', '', 'จอรับสัญญาณแสดงผล', '', 'ชิ้นทดสอบวัสดุ', 4, 1, '30103'),
(620, '', 'หัวตรวจสอบชนิดใดที่ทำหน้าที่เป็นตัวส่งและรับคลื่นอัลตราโซนิก', '', 'หัวตรวจสอบตรง', '', 'หัวตรวจสอบแบบ TR', '', 'หัวตรวจสอบเอียง', '', 'หัวตรวจสอบรัศมีโค้ง', 2, 1, '30103'),
(621, '', 'เมื่อทำการเปิดเครื่องตรวจสอบอัลตราโซนิกเพื่อทำงานใหม่ทุกครั้ง ผู้ปฏิบัติการตรวจสอบจะต้องดำเนินการอย่างไร\r\n', '', 'ปรับตั้งสัญญาณคลื่นกับแท่งทดสอบ', '', 'ปรับตั้งสัญญาณคลื่นกับแท่งทดสอบมาตรฐาน', '', 'ปรับตั้งสัญญาณคลื่นกับแท่งปรับมาตรฐาน', '', 'ปรับตั้งสัญญาณคลื่นกับแท่งเปรียบเทียบ', 3, 1, '30103'),
(622, '', 'สัญลักษณ์ SR เป็นชื่อย่อของอะไร', '', 'เอคโค  ', '', 'สเกลเฟคเตอร์  ', '', 'ระยะทางคลื่น', '', 'ตำแหน่งสเกล  ', 2, 1, '30103'),
(623, '', 'การส่งผ่านคลื่นอัลตราโซนิก ที่ทำหน้าที่เปลี่ยนพลังงานกลเป็นพลังงานไฟฟ้า คือการส่งผ่านคลื่นแบบใด', '', 'การส่งผ่านคลื่นเสียง', '', 'การสะท้อนคลื่นเสียงกลับ', '', 'การรีโซแนนซ์', '', 'การส่งผ่านคลื่นสนามแม่เหล็ก', 2, 1, '30103'),
(624, '', 'ในการทดสอบคลื่นเสียงกระทบกับจุดบกพร่องที่เกิดขึ้นภายในเนื้องของวัสดุ คลื่นจะสะท้อนกลับไปยังหัวส่งคลื่นและจะแสดงผลในจอรับภาพอย่างไร\r\n', '', 'คลื่นเสียงส่งผ่านมายังหัวรับคลื่นมาก จุดบกพร่องใหญ่สัญญาณ Echo มาก', '', 'คลื่นเสียงส่งผ่านมายังหัวรับคลื่นน้อย จุดบกพร่องใหญ่สัญญาณ Echo มาก', '', 'คลื่นเสียงส่งผ่านมายังหัวรับคลื่นมาก จุดบกพร่องใหญ่สัญญาณ Echo น้อย', '', 'คลื่นเสียงส่งผ่านมายังหัวรับคลื่นน้อย จุดบกพร่องใหญ่สัญญาณ Echo น้อย', 4, 1, '30103'),
(625, '', 'ข้อใดกล่าวผิดในการบันทึกรายงานผลการตรวจสอบด้วยคลื่นอัลตรโซนิก', '', 'บันทึกภาพถ่ายคลื่นที่แสดงบนจอรับภาพ CRT', '', 'บันทึกตำแหน่งจุดบกพร่อง', '', 'บันทึกความสูงของขุดพร่อง', '', 'บันทึกขั้นตอนในการทดสอบ', 4, 1, '30103'),
(626, '', 'ข้อใดกล่าวถึงการตรวจสอบด้วยรังสี(RT)ได้อย่างถูกต้อง', '', 'ใช้รังสีเอกซ์ (X-Ray) ', '', 'ใช้รังสีแกมม่า (Gramma-Ray)', '', 'ฉายรังสีผ่านเนื้อวัสดุงานแล้วทำปฎิกิริยากับฟิล์มที่อยู่', '', 'ถูกทุกข้อ', 4, 1, '30103'),
(627, '', 'เครื่อง  Gramma-Ray  ประกอบด้วยส่วนสำคัญมีกี่ส่วน', '', '1  ส่วน', '', '2  ส่วน', '', '3  ส่วน', '', '4  ส่วน', 2, 1, '30103'),
(628, '', 'ฟองอากาศทั่วไป (Porosity)ในเนื้อเชื่อม เมื่อทำการถ่ายภาพรังสี ภาพที่ปรากฎบนฟิล์มภาพถ่ายรังสีจะมีลักษณะเป็นอย่างไร', '', 'จุดสีขาวสว่างจ้า', '', 'จุดสีเทามืดดำรูปร่างต่างกัน', '', 'จุดดำหรือแนวมืดดำเข้ม', '', 'จุดดำขนาดเล็กจำนวนมากอยู้ใกล้กัน', 3, 1, '30103'),
(629, '', 'การตกแต่งชิ้นงานทดสอบแนวเชื่อมแบบทำลายสภาพด้วยการตัดโค้ง ควรทำสิ่งใดเป็นอันดับแรก	', '', 'ขัดด้วยกระดาษทราย', '', 'เจียระไน', '', 'นำชิ้นงานตั้งบนเครื่องทดสอบ', '', 'ตกแต่งด้วยตะไบ', 4, 1, '30103'),
(630, '', 'จุดวาบไฟและจุดติดไฟต่ำจะมีผลต่อเครื่องยนต์ในกรณีใดมากที่สุด', '', 'ช่วยให้เครื่องยนต์มีอัตราเร็วสูง', '', 'ช่วยให้เครื่องยนต์ติดได้ง่าย', '', 'ช่วยให้เครื่องยนต์มีอัตราการน๊อคต่ำ', '', 'ช่วยให้เครื่องยนต์มีแรงม้าสูงขึ้น', 4, 1, '30101'),
(631, '', 'ข้อใดแสดงถึงความสามารถในการติดไฟ', '', 'การกระจายเป็นละอองเมื่อติดไฟ', '', 'เครื่องยนต์สตาร์ทติดเร็วขณะอุณหภูมิต่ำ', '', 'น้ำมันสามารถระเหยได้ง่ายแล้วติดไฟ', '', 'การเป็นไอได้เร็วและติดไฟง่าย', 1, 1, '30101'),
(632, '', 'การทดสอบหาค่าความร้อนเชื้อเพลิงจะได้ค่าความร้อนเชื้อเพลิงขั้นสูงเมื่อสภาพการทดสอบเป็นอย่างไร\r\n', '', 'ผลต่างระหว่างอุณหภูมิห้องกับอุณหภูมิหลังการทดสอบสูงมาก', '', 'ไอน้ำจากการทดสอบกลั่นตัวเป็นหยดน้ำทั้งหมด', '', 'มวลเชื้อเพลิงสันดาปทั้งหมด', '', 'ความดันจากการสันดาปสูงกว่าความดันจากบรรยากาศมาก', 3, 1, '30101'),
(633, '', 'ค่าความร้อนของเชื้อเพลิงมีประโยชน์อย่างไร', '', 'ทำให้เลือกใช้เชื้อเพลิงได้อย่างถูกต้อง', '', 'ทำให้แบ่งประเภทของเชื้อเพลิงได้', '', 'ทำให้เก็บรักษาเชื้อเพลิงได้ถูกต้อง', '', 'ทำให้ประหยัดเงินซื้อเชื้อเพลิง', 4, 1, '30101'),
(634, '', 'การทดสอบความหนืดน้ำมันหล่อลื่นโดยใช้ Saybolt  Viscometer มีวิธีการทดสอบออย่างไร\r\n', '', 'หาน้ำหนักของน้ำมันที่ไหลผ่านท่อความฝืด', '', 'วัดปริมาณน้ำมันที่ไหลผ่านรูเล็ก ๆ ขนาดต่าง ๆ', '', 'จับเวลาการไหลของน้ำมันจำนวนหนึ่งที่ไหลผ่านรูเล็ก ๆ', '', 'หาความแตกต่างของอุณหภูมิเมื่อความหนืดเปลี่ยนแปลง', 2, 1, '30101'),
(635, '', 'ความดันที่ปรากฏบนเกจวัดความดันคือข้อใด', '', 'ความดันที่เท่ากับความดันบรรยากาศ', '', 'ความดันที่สูงกว่าความดันบรรยากาศ', '', 'ความดันที่ต่ำกว่าความดันบรรยากาศ', '', 'ความดันที่เท่ากับความดันสมบูรณ์', 1, 1, '30101'),
(636, '', 'เครื่องมือที่ใช้วัดความดันบรรยากากาศคือเครื่องมือใด', '', 'โมโนมิเตอร์ (Monometer)', '', 'บารอมิเตอร์ (Barometer)', '', 'ไฮโดรมิเตอร์ (Hydrometer)', '', 'ไซโครมิเตอร์ (Saicrometer)', 4, 1, '30101'),
(637, '', 'อุปกรณ์วัดอัตราการไหลที่ให้ค่าที่อ่านน่าเชื่อถือมากที่สุดคืออุปกรณ์ใด', '', 'Measuring  Tank', '', 'Variable  Area Flow  Meter', '', 'Flow  Meter', '', 'ISA  Nozzle', 4, 1, '30101'),
(638, '', 'อัตราการไหลของของไหลในท่อเป็นองค์ประกอบของข้อใด', '', 'การสูญเสียพลังงานการไหลแบบราบเรียบ', '', 'การสูญเสียความเร็วเฉลี่ยในท่อ', '', 'การสูญเสียพลังงานการไหลแบบปั่นป่วน', '', 'การสูญเสียความดันเนื่องจากอุณหภูมิ', 4, 1, '30101'),
(639, '', 'ความหมายของ Pressure  Head  คือข้อใด\r\n', '', 'ความสูงของของเหลวภายใต้ความดันคงที่', '', 'ความสูงของของเหลว ณ ผิวอิสระ', '', 'ความสูงของของเหลวที่วัดจากระดับน้ำทะเล', '', 'ความสูงของของเหลวภายใต้ความดันบรรยากาศ', 3, 1, '30101'),
(640, '', 'ผลการทดสอบประสิทธิภาพของปั๊มน้ำ จะมีลักษณะอย่างไร', '', 'เมื่อความดันเพิ่มขึ้น อัตราการไหลจะเพิ่มขึ้น', '', 'เมื่อความดันเพิ่มขึ้น อัตราการไหลจะลดลง', '', 'เมื่อความดันปั๊มเพิ่มขึ้น  พลังงานขับปั๊มจะลดลง', '', 'เมื่อความดันเพิ่มขึ้น ความสูญเสียในท่อจะลดลง', 4, 1, '30101'),
(641, '', 'การทดสอบในข้อใด  เป็นการทดสอบสมรรถนะของเครื่องยนต์', '', 'การวัดความเร็วของเครื่องยนต์', '', 'การหาอัตราเร่งของเครื่องยนต์', '', 'การคำนวณภาระของเครื่องยนต์', '', 'การหาอัตราการสิ้นเปลืองน้ำมันเชื้อเพลิง', 1, 1, '30101'),
(642, '', 'จากการทดสอบกำลังของเครื่องยนต์ จะพบความสัมพันธ์ของตัวแปรต่าง ๆ ตามข้อใด', '', 'จุดที่กำลังม้าเบรกสูงสุด ไม่ใช่จุดที่ความเร็วรอบสูงสุด', '', 'กำลังม้าเบรกจะสูงสุด เมื่อรอบเครื่องยนต์สูงสุด', '', 'แรงบิดจะสูงสุด เมื่อรอบเครื่องยนต์สูงสุด', '', 'ที่ความเร็วรอบต่ำสุด จะมีแรงบิดสูงสุด', 4, 1, '30101'),
(643, '', 'ถ้าเครื่องยนต์ใช้น้ำมันเชื้อเพลิง 3 cc. ภายในเวลา 36 วินาที จะมีอัตราความสิ้นเปลืองน้ำมันเชื้อเพลิงเท่าไร', '', '0.3  l/hr', '', '0.5  l/hr', '', '3.0  l/hr', '', '5.0  l/hr', 4, 1, '30101'),
(644, '', 'การวัดอัตราการไหลของอากาศเข้าสู่เครื่องยนต์ โดยใช้ Orifice  Meter จะต้องทราบข้อมูลใด', '', 'ความเร็วของอากาศที่ผ่าน  Orifice Meter', '', 'เส้นผ่านศูนย์กลาง  Air Chamber', '', 'ปริมาตรของ  Air Chamber', '', 'อุณหภูมิของเครื่องยนต์', 1, 1, '30101'),
