(925, '', 'ข้อใดเป็นประโยชน์ของ DFD (Data Flow Diagram)\r\n', '', 'แสดงให้เห็นขั้นตอนการสร้างระบบ\r\n', '', 'แสดงให้เห็นขั้นตอนการออกแบบระบบ\r\n', '', 'แสดงการให้เห็นขั้นตอนการวิเคราะห์ปัญหา\r\n', '', 'แสดงให้เห็นถึงข้อมูลและการเคลื่อนไหวของข้อมูลในระบบ\r\n', 4, 1, '4901'),
(926, '', 'ข้อใดเป็นลักษณะการประมวลผลแบบไคลเอนต์ - เซิร์ฟเวอร์\r\n', '', 'การประมวลผลทุกอย่างในเครื่องเดียวกัน\r\n', '', 'การนำเครื่องไคลเอนต์ที่มีประสิทธิภาพใช้แทนเครื่องเทอร์มินัล\r\n', '', 'การนำเครื่องไคลเอนต์ที่มีประสิทธิภาพใช้แทนเครื่องเซิร์ฟเวอร์\r\n', '', 'การแบ่งหน้าที่การประมวลผลระหว่างเครื่องเซิร์ฟเวอร์กับเครื่องไคลเอนต์\r\n', 4, 1, '4901'),
(927, '', 'การพัฒนาระบบสารสนเทศมีลักษณะอย่างไร\r\n', '', 'การผลิตซอฟต์แวร์ที่มีคุณภาพ\r\n', '', 'การคัดเลือกฮาร์ดแวร์ให้เหมาะสม\r\n', '', 'การเขียนผังงานโครงสร้างแบบใหม่\r\n', '', 'การนำซอฟต์แวร์มาช่วยในระบบงานเดิม\r\n', 4, 1, '4901'),
(928, '', 'ข้อใดเป็นองค์ประกอบหนึ่งของการติดตั้งระบบเพื่อใช้งาน (Installing the system) หรือการนำระบบสารสนเทศไปใช้\r\n', '', 'การวิเคราะห์ระบบ\r\n', '', 'การออกแบบระบบ\r\n', '', 'การกำหนดปัญหาระบบ\r\n', '', 'การจัดทำเอกสารประกอบระบบ\r\n', 4, 1, '4901'),
(929, '', 'ข้อใดไม่ใช่การทดสอบการทำงานของโปรแกรมคอมพิวเตอร์\r\n', '', 'ทดสอบการติดตั้งโปรแกรม(SOFTWARE SETUP TEST)\r\n', '', 'ทดสอบการทำงานของโปรแกรมแต่ละโปรแกรม (UNIT TEST)\r\n', '', 'ทดสอบกับข้อมูลจริงเพื่อยอมรับระบบโดยผู้ใช้ระบบ (ACCEPTANCE TEST)\r\n', '', 'ตรวจสอบความถูกต้องของโปรแกรมตั้งแต่เริ่มต้นจนได้ผลลัพธ์ (SYSTEM TEST)\r\n', 1, 1, '4901'),
(930, '', 'ในกระบวนการของการวิเคราะห์และออกแบบระบบDiagram ใดของ UML ที่ใช้แสดงพฤติกรรมของคลาสหรือขั้นตอนการทำงาน\r\n', '', 'Activity Diagram \r\n', '', 'Use Case Diagram\r\n', '', 'Sequence Diagram\r\n', '', 'Component Diagram\r\n', 3, 1, '4901'),
(931, '', 'โปรแกรมในข้อใดไม่ใช่DBMS (Database Management System)\r\n', '', 'DB2\r\n', '', 'EXCEL\r\n', '', 'ACCESS\r\n', '', 'ORACLE\r\n', 2, 1, '4901'),
(932, '', 'Data Model ที่ใช้เป็นแนวคิดในการออกแบบระบบฐานข้อมูลเชิงสัมพันธ์คือข้อใด\r\n\r\n', '', 'Network model\r\n', '', 'Relational model\r\n', '', 'Hierarchical model\r\n', '', 'Entity relationship model\r\n', 4, 1, '4901'),
(933, '', 'หลักการของกฎ Entity Integrity Rule คือข้อใด\r\n', '', 'ข้อมูลแต่ละแอททริบิวท์ต้องไม่ซ้ำกัน\r\n', '', 'ข้อมูลของ Primarykeyต้องไม่เป็นค่าว่าง (NULL)\r\n', '', 'ข้อมูลแต่ละแอททริบิวท์ต้องไม่เป็นค่าว่าง (NULL)\r\n', '', 'ข้อมูลแต่ละแอททริบิวท์ต้องอยู่ภายในขอบเขตที่กำหนด\r\n', 2, 1, '4901'),
(934, '', 'ในการออกแบบระบบฐานข้อมูล ข้อใดกล่าวถูกต้องเกี่ยวกับกฎ REFERENTIAL INTEGRITY\r\n', '', 'ข้อมูลในรีเลชั่นทางฝั่ง FK และ PK ต้องเป็นข้อมูลที่มีจำนวนรายการเท่ากัน\r\n', '', 'ข้อมูลในรีเลชั่นทางฝั่ง PK ต้องเหมือนกับข้อมูลในรีเลชั่นที่ฝั่ง FK ทุกประการ\r\n', '', 'ข้อมูลในรีเลชั่นทางฝั่ง FK ต้องมีข้อมูลเหมือนกับในรีเลชั่นที่ฝั่ง PK ทุกรายการ\r\n', '', 'ข้อมูลในรีเลชั่นทางฝั่ง FK ทุกรายการต้องเป็นข้อมูลมีอยู่จริงในรีเลชั่นที่ฝั่ง PK \r\n', 4, 1, '4901'),
(935, '', 'ข้อใดมีความสัมพันธ์กันแบบ ONE TO ONE\r\n', '', 'พ่อกับลูก\r\n', '', 'ลูกค้ากับร้านค้า\r\n', '', 'ครูกับแผนกวิชา\r\n', '', 'ผู้ว่าราชการกับจังหวัด\r\n', 4, 1, '4901'),
(936, '', 'คำสั่ง SQL ในข้อใดที่มีความหมายถูกต้อง\r\n', '', 'Insert = add column \r\n', '', 'Alter = change table\r\n', '', 'Drop = delete record\r\n', '', 'Delete = delete table\r\n', 2, 1, '4901'),
(937, '', 'ในการใช้งานระบบฐานข้อมูลหากต้องการเพิ่มค่าในช่องฟิลด์ salary ขึ้นอีก 15% ในตาราง Employee ต้องเขียน คำสั่งSQL อย่างไร\r\n', '', 'Update Employee Set salary = salary + salary * 0.15\r\n', '', 'Select salary = salary + salary * 0.15  From Employee\r\n', '', 'Insert into Employee Where salary = salary + salary * 0.15\r\n', '', 'Update into Employee Where salary = salary + salary * 0.15\r\n', 1, 1, '4901'),
