(970, '', 'ข้อใดเป็นการวิเคราะห์ข้อมูลเพื่อนำไปใช้ประโยชน์ในงานจัดซื้อ\r\n', '', 'การให้บริการลูกค้า  การเลือกแหล่งขาย\r\n', '', 'การพยากรณ์ยอดขาย  การเลือกแหล่งขาย\r\n', '', 'การให้บริการลูกค้า   ระดับปริมาณสินค้าคงคลัง \r\n', '', 'การเลือกแหล่งขาย    ระดับปริมาณสินค้าคงคลัง\r\n', 4, 1, '4214'),
(971, '', 'ต้นทุนใดที่ไม่เปลี่ยนแปลงไปตามระดับของการดำเนินงานหรือปริมาณการผลิตในช่วงของการดำเนินงานระดับหนึ่ง\r\n', '', 'ต้นทุนส่วนเพิ่ม\r\n', '', 'ต้นทุนคงที่\r\n', '', 'ต้นทุนทางตรง\r\n', '', 'ต้นทุนผันแปร\r\n', 2, 1, '4214'),
(972, '', 'ข้อใดเป็นต้นทุนที่นำมาพิจารณาในตัวแบบการสั่งซื้อที่ประหยัดที่สุด (EOQ)\r\n', '', 'ต้นทุนในการสั่งซื้อ กับ ต้นทุนในการเก็บรักษา\r\n', '', 'ต้นทุนเงินทุนหมุนเวียน กับ ต้นทุนในการสั่งซื้อ\r\n', '', 'ต้นทุนป้องกันความเสี่ยง กับ ต้นทุนในการเก็บรักษา\r\n', '', 'ต้นทุนเงินทุนหมุนเวียน กับ ต้นทุนในการเก็บรักษา\r\n', 1, 1, '4214'),
(973, '', 'ข้อใดเป็นสมมติฐานที่ถูกต้องของตัวแบบปริมาณการสั่งซื้อที่ประหยัดที่สุด (EOQ)\r\n', '', 'เวลานำ (Lead Time) ในการสั่งซื้อไม่คงที่\r\n', '', 'ไม่มีสินค้าระหว่างทางและไม่มีสินค้าขาดสต็อก\r\n', '', 'ต้องมีการสั่งซื้อสินค้าในแต่ละครั้งไม่ต่ำกว่า 2 ชนิด\r\n', '', 'ราคาสินค้าที่สั่งซื้อจะเปลี่ยนแปลงตามปริมาณการสั่งซื้อ\r\n', 2, 1, '4214'),
(974, '', 'ปัจจัยที่มีอิทธิพลต่อต้นทุนคือข้อใด\r\n', '', 'บรรจุภัณฑ์\r\n', '', 'มูลค่าของสินค้า\r\n', '', 'น้ำหนักและขนาดของสินค้า\r\n', '', 'พื้นที่ที่ใช้ในการขนส่งสินค้า\r\n', 4, 1, '4214'),
(975, '', 'ข้อใดเป็นต้นทุนคงที่ของการขนส่งทั้งหมด\r\n', '', 'ค่าน้ำมันยานพาหนะ ค่าบริหารจัดการ\r\n', '', 'ค่าล่วงเวลาของพนักงาน ค่าเสื่อมราคา\r\n', '', 'ค่าเบี้ยประกันภัยยานพาหนะ ค่าเสื่อมราคา\r\n', '', 'ค่าน้ำมันหล่อลื่น ค่าบำรุงรักษา', 3, 1, '4214'),
(976, '', 'บริษัท พีพี โลจิสติกส์ จำกัด  ดำเนินการให้บริการด้านการกระจายสินค้า  พบว่า ในหนึ่งเดือน  มีต้นทุนด้านบุคลากร 120,000 บาท ด้านพื้นที่ 50,000 บาท และต้นทุนด้านเครื่องจักร อุปกรณ์ 80,000 บาท โดยคิดค่าบริการจากลูกค้าพาเลตละ 325 บาท ในการดำเนินงานมีต้นทุน 75 บาทต่อพาเลต ข้อใดคือมูลค่าการให้บริการที่เป็นจุดคุ้มทุน\r\n', '', '292,500  บาท\r\n', '', '308,750  บาท\r\n', '', '325,000 บาท\r\n', '', '357,500 บาท\r\n\r\n', 3, 1, '4214'),
(977, '', 'ข้อใดเป็นขั้นตอนที่ถูกต้องของการเตรียมเอกสาร และการเตรียมพื้นที่ในการรับสินค้า\r\n', '', 'รับเอกสารการรับสินค้า  ตรวจดูรายละเอียดของเอกสาร  นำข้อมูลปริมาณงานมาคำนวณ  จำนวนรับวัสดุ อุปกรณ์ แล', '', 'รับเอกสารการรับสินค้า  ตรวจสอบทะเบียนรถตรงกับที่ระบุไว้ในเอกสาร ยกสินค้าลงหรือยกสินค้าลงบน Pallet ที', '', 'รับเอกสารการรับสินค้า  นำข้อมูลปริมาณงานมาคำนวณ  จำนวนรับวัสดุ อุปกรณ์ และเครื่องมือ กำหนดพื้นที่ที่', '', 'รับเอกสารการรับสินค้า  ตรวจสอบ Seal ตู้สินค้า และเปิดประตูตู้สินค้า ยกสินค้าลงหรือยกสินค้าลงบน Palle', 1, 1, '4214'),
(978, '', 'ข้อใดเป็นวิธีการตรวจรับและการนับสินค้าที่ถูกต้อง\r\n', '', 'รับสินค้า  ตรวจสอบใบส่งสินค้า   นำสินค้าเก็บเข้าคลังสินค้า   นับจำนวนสินค้า\r\n', '', 'ตรวจสอบใบส่งสินค้า   นับจำนวนสินค้า   รับสินค้า  นำสินค้าเก็บเข้าคลังสินค้า\r\n', '', 'ตรวจสอบใบส่งสินค้า  รับสินค้า   นับจำนวนสินค้า   นำสินค้าเก็บเข้าคลังสินค้า\r\n', '', 'นับสินค้า   ตรวจสอบใบส่งสินค้า   รับสินค้า   นำสินค้าเก็บเข้าคลังสินค้า\r\n', 2, 1, '4214'),
(979, '', 'ข้อใดเป็นหลักการเคลื่อนย้ายสินค้าในคลังสินค้า\r\n', '', 'เคลื่อนย้ายสินค้าให้เป็นไปตามประสบการณ์ของผู้ปฏิบัติ\r\n', '', 'มีการแก้ปัญหาเฉพาะหน้าในการปฏิบัติงาน\r\n', '', 'แปลงหน่วยสินค้าทุกครั้งก่อนการเคลื่อนย้าย\r\n', '', 'บริหารพื้นที่ให้เกิดประโยชน์มากที่สุด\r\n', 4, 1, '4214'),
(980, '', 'ขั้นตอนใดที่ไม่มีการปฏิบัติในคลังสินค้า \r\n \r\n', '', 'การเก็บสินค้า (Put-away)\r\n', '', 'การหยิบสินค้า (Order picking)\r\n', '', 'การควบคุมสินค้าคงคลัง (Inventory control)\r\n', '', 'การคัดแยก และแปลงหน่วย (Selection and Letdown)\r\n', 4, 1, '4214'),
(981, '', 'ควรใช้เครื่องมือและอุปกรณ์ขนถ่ายวัสดุชนิดใดสำหรับทางเดินที่แคบมาก\r\n', '', 'รถยกลากไฟฟ้าแบบเดินตาม  (Electric pallet truck) \r\n', '', 'รถยกสูงแบบนั่งขับ (Counter Stacker)\r\n', '', 'รถยกสูงแบบใช้ไฟฟ้า (Electric Stacker)\r\n', '', 'รถยกลาก (stacker hand ', 4, 1, '4214'),
(982, '', 'อุปกรณ์เครื่องมือชนิดใดใช้ประโยชน์ในงานคลังสินค้ามากที่สุด \r\n', '', 'พาเลต\r\n', '', 'รางเลื่อน\r\n', '', 'เครื่องพิมพ์บาร์โค้ด\r\n', '', 'รถ Fork Lift  ขนาดเล็ก\r\n', 4, 1, '4214'),
(983, '', 'ข้อใดเป็นขนาดการผลิตที่ประหยัด (Economy of scale) ในอุตสาหกรรมการขนส่ง\r\n', '', 'นำเทคโนโลยีมาใช้กับการขนส่ง\r\n', '', 'มีระดับการให้บริการการขนส่งที่แตกต่างกัน\r\n', '', 'จัดหาสิ่งอำนวยความสะดวกมาสนับสนุนการขนส่ง\r\n', '', 'เลือกใช้ยานพาหนะมีขนาดที่เหมาะสม และมีจำนวนเที่ยววิ่งจำนวนมาก\r\n', 4, 1, '4214'),
(984, '', 'ข้อใดเป็นความแตกต่างระหว่างการบริการขนส่งสินค้า กับ การบริการขนส่งผู้โดยสาร\r\n', '', 'ผู้ใช้บริการ\r\n', '', 'เส้นทางในการขนส่ง\r\n', '', 'ปฏิกิริยาการตอบสนอง\r\n', '', 'สถานีที่ใช้ในการขนส่ง\r\n', 3, 1, '4214'),
(985, '', 'ลักษณะการขนส่งข้อใดทำให้สินค้ามีมูลค่าเพิ่มขึ้น  \r\n', '', 'การนำสินค้ามาคัดแยก หรือแปลงหน่วย\r\n', '', 'การนำสินค้าไปยังสถานที่ที่มีความต้องการ\r\n', '', 'การทำให้สินค้าและบริการมีความแตกต่างกัน\r\n', '', 'การทำให้แหล่งผลิตเคลื่อนที่มาอยู่ใกล้กับผู้บริโภค\r\n', 2, 1, '4214'),
(986, '', 'ข้อใดเป็นหลักการรวมกลุ่มการขนส่งในกลุ่มเศรษฐกิจ\r\n', '', 'เพิ่มมาตรการทางการค้า และการขนส่งร่วมกัน\r\n', '', 'จัดเส้นทางการขนส่งและการนำเข้ากับประเทศคู่ค้า\r\n', '', 'ร่วมมือในการผลิตสินค้าและบริการ การจัดจำหน่าย การขนส่ง\r\n', '', 'ขจัดอุปสรรคทางการค้าและให้ปัจจัยการผลิตเคลื่อนย้ายอย่างเสรี', 4, 1, '4214'),
(987, '', 'การตัดสินใจเลือกชนิดของยานพาหนะ และอุปกรณ์ประกอบพาหนะขึ้นอยู่กับปัจจัยใดมากที่สุด\r\n', '', 'นโยบาย และแผนงานขององค์กร\r\n', '', 'จำนวนสินค้า  และสภาพดินฟ้าอากาศ \r\n', '', 'ลักษณะของสินค้า  และระยะทางในการขนส่ง\r\n', '', 'เส้นทางในการจัดส่ง  ขนาด และน้ำหนักของสินค้า\r\n\r\n', 4, 1, '4214'),
(988, '', 'โรงงานเจบี  ผลิตน้ำผลไม้ มีแหล่งวัตถุดิบที่ใช้ในการผลิตอยู่ห่างจากตลาด 100 กิโลเมตร  อัตราค่าบริการตันละ 1 บาท ต่อระยะทาง 1 กิโลเมตร  เมื่อผลิตเป็นน้ำผลไม้น้ำหนักจะลดลงจาก 100 ตัน เหลือ 80 ตัน จากกรณีศึกษา โรงงานเจบี ควรตั้งโรงงานไว้ในตำแหน่งใด\r\n', '', 'ใกล้ตลาด\r\n', '', 'ใกล้แหล่งวัตถุดิบ\r\n', '', 'กึ่งกลางระหว่างตลาด และแหล่งวัตถุดิบ\r\n', '', 'ตั้งตามนโยบายของผู้บริหารและผู้มีส่วนเกี่ยวข้อง\r\n', 2, 1, '4214'),
(989, '', 'สินค้าเคลื่อนไหวเร็ว มักใช้การขนส่งในรูปแบบใด \r\n', '', 'แบบต่อเนื่องหลายรูปแบบ\r\n', '', 'แบบพิจารณาตามขนาดของลูกค้า\r\n', '', 'แบบใช้ศูนย์กระจายสินค้าเป็นจุดผ่าน\r\n', '', 'แบบจากโรงงานไปให้ลูกค้าหลายราย\r\n', 3, 1, '4214'),
(990, '', 'ข้อใดเป็นวิธีการจัดซื้อที่เหมาะสมที่สุด\r\n', '', 'เลือกซื้อจากแหล่งขายที่ใกล้ที่สุด\r\n', '', 'เลือกซื้อตามดุลยพินิจของผู้บริหาร\r\n', '', 'เลือกซื้อจากแหล่งขายที่ให้ส่วนลดมากที่สุด\r\n', '', 'เลือกซื้อให้เหมาะสมตามสภาพความต้องการใช้\r\n', 4, 1, '4214'),
(991, '', 'ข้อใดเป็นกระบวนการเริ่มต้นของการจัดซื้อ\r\n', '', 'ศรีประทุมทำเอกสาร PR ส่งฝ่ายจัดซื้อ\r\n', '', 'ศรีประไพทำเอกสาร PO ส่งฝ่ายจัดซื้อ\r\n', '', 'ศรีประจันทร์ทำ INVOICE ส่งฝ่ายจัดซื้อ\r\n', '', 'ศรีประภาอยู่ฝ่ายจัดซื้อส่งใบ PR ไปยังฝ่ายต่าง ๆ\r\n', 1, 1, '4214'),
(992, '', 'ข้อใดเป็นการเจรจาต่อรองที่มีโอกาสประสบความสำเร็จมากที่สุด\r\n\r\n', '', 'สมใจแสดงท่าทีอยากทำการเจรจาต่อรองกับคู่เจรจา\r\n', '', 'สมภพเจรจาต่อรองให้เป็นประโยชน์ต่อองค์กรของตนเอง\r\n', '', 'สมพรใช้การยั่วยุแก่คู่เจรจารีบตอบตกลงตามข้อเสนอ\r\n', '', 'สมศรีทำการศึกษาข้อมูลเกี่ยวกับคู่เจรจา และเข้าใจจุดแข็งจุดอ่อนของตนเองก่อน\r\nการเจรจาต่อรอง\r\n', 4, 1, '4214'),
(993, '', 'เพื่อขจัดปัญหาการจัดซื้อฉุกเฉินหรือซื้อจำนวนไม่มาก  ธุรกิจควรกำหนดวิธีการจัดซื้ออย่างจึงเหมาะสม\r\n', '', 'กำหนดขั้นตอนเกี่ยวกับเอกสารในการจัดซื้อ \r\n', '', 'คัดเลือกรายละเอียดและความต้องการของฝ่ายจัดซื้อ\r\n', '', 'วางแผนการจัดซื้ออย่างรัดกุม ทุกช่วงเวลาของการปฏิบัติงาน\r\n', '', 'กำหนดความต้องการและรายละเอียดคุณสมบัติของสินค้า\r\n', 3, 1, '4214'),
(994, '', 'สินค้าคงคลังประเภทใดที่คาดการณ์ว่าอาจขาดแคลนและมีราคาเพิ่มขึ้นในอนาคต\r\n', '', 'สินค้าที่เก็บไว้ตามฤดูกาล (Seasonal Stock)\r\n', '', 'สินค้าที่เก็บไว้เพื่อเก็งกำไร (Speculative Stock)\r\n', '', 'สินค้าระหว่างการขนส่ง (In-transit Inventories)\r\n', '', 'สินค้าเพิ่มเติมหรือสินค้าคงคลังปลอดภัย (Buffer or Safety Stock)\r\n', 2, 1, '4214'),
(995, '', 'ข้อความใดเกี่ยวข้องกับสินค้าคงคลัง\r\n', '', 'การบริหารวัตถุดิบที่ต้องมีการเคลื่อนย้าย และที่พัก\r\n', '', 'การบริหารจัดการ เสบียงสำหรับโรงงาน  กระบวนการผลิต  และการกระจายสินค้าไปยังลูกค้า\r\n', '', 'การจัดส่งสินค้าให้กับลูกค้าอย่างถูกต้องทั้งจำนวน สภาพ สถานที่ และต้องคำนึงถึงต้นทุนที่เหมาะสมที่สุด\r', '', 'การบริหารสถานการณ์ทางการแข่งขันเพื่อสร้างความได้เปรียบ ความเหมาะสม ความพอดี  ในการจัดการสินค้าอย่างเ', 2, 1, '4214'),
(996, '', 'การเตรียมการส่งออกสินค้าแบบ Re-export คือข้อใด\r\n', '', 'การขออนุญาตเป็นผู้ผลิตเพื่อการส่งออก\r\n', '', 'การส่งออกสินค้าซ้ำ ๆ ไปยังประเทศใดประเทศหนึ่ง\r\n', '', 'การนำเข้าสินค้ามาจากต่างประเทศและส่งออกไปยังอีกประเทศหนึ่ง\r\n', '', 'การนำสินค้าเข้ามาทำการผลิต และจำหน่ายออกไปยังอีกประเทศหนึ่ง\r\n', 3, 1, '4214'),
(997, '', 'เอกสารทางการค้าใดที่ผู้ซื้อนำไปใช้ติดต่อกับธนาคารเพื่อขอเปิด L', '', 'C  \r\n', '', 'ใบเสนอราคา  (Proforma Invoice)\r\n', '', 'ใบตราส่งสินค้า (Bill of  Lading)\r\n', '', 'ใบรับรองแหล่งกำเนิดของสินค้า (Certificate of Origin)\r\n', 1, 1, '4214'),
(998, '', 'จุดเด่นที่สำคัญของระบบ E-CUSTOMS PAPERLESS คือข้อใด\r\n', '', 'การส่งข้อมูลผ่านระบบ Internet ได้โดยตรง\r\n', '', 'เป็นเทคโนโลยีที่ผู้ประกอบการนำเข้าและส่งออกสามารถดำเนินการได้ด้วยตนเอง\r\n', '', 'ช่วยลดจำนวนพนักงานในการปฏิบัติงานจัดทำเอกสารลง ทำให้ประหยัดค่าใช้จ่าย\r\n', '', 'ลดการป้อนข้อมูลที่ซ้ำซ้อน สามารถติดต่อส่งข้อมูลตรงไปยังถึงกรมศุลกากรเพื่อขอรหัสผ่าน Gateway โดยไม่ต้', 4, 1, '4214'),
(999, '', 'ข้อตกลง FTA หรือเขตการค้าเสรี เป็นข้อตกลงในลักษณะใด\r\n', '', 'ความร่วมมือระหว่างผู้นำเข้าและส่งออกของประเทศที่ตกลงอยู่ในเขตการค้าเสรี\r\n', '', 'เป็นข้อตกลงการค้าที่เกิดขึ้นในกลุ่มของประเทศที่อยู่ในภูมิภาคเดียวกัน เช่น กลุ่มอาเซียน\r\n', '', 'เป็นข้อตกลงที่เกิดขึ้นแบบทวิภาคี หรือกลุ่มประเทศ (พหุภาคี) เพื่อร่วมมือกันขจัดอุปสรรคทางการค้าทั้งที', '', 'เป็นสนธิสัญญาความร่วมมือกันในกลุ่มของประเทศที่เป็นพันธมิตรกันในด้านใดด้านหนึ่งเพื่อขจัดข้อขัดแย้งด้า', 3, 1, '4214'),
(1000, '', 'ข้อใดเป็นประเด็นสำคัญของข้อตกลงเงื่อนไขการส่งมอบสินค้าระหว่างประเทศ หรือ Incoterm \r\n\r\n', '', 'ช่วยให้เกิดความถูกต้องของระบบการจัดการภาษีศุลกากรเป็นระบบเดียวกันทุกประเทศ\r\n', '', 'การสร้างระบบการส่งมอบสินค้าระหว่างประเทศในทุกระบบการขนส่งที่เกิดขึ้นในโลกให้ถูกที่ ถูกเวลา ประหยัดต้', '', 'การสร้างความสมดุลของระบบการส่งมอบสินค้าระหว่างประเทศเพื่อให้เกิดความเป็นธรรมแก่ทุกฝ่ายที่เกี่ยวข้อง\r', '', 'เพื่อให้คู่ค้าทั้งผู้ซื้อ และผู้ขายทราบถึงขอบเขต ความรับผิดชอบภาระค่าใช้จ่าย และความเสี่ยงต่าง ๆ  โด', 4, 1, '4214'),
(1001, '', 'กระบวนการในการวางแผนดำเนินการ และควบคุมประสิทธิภาพในการไหลเวียนสินค้า บริหารต้นทุน การขนส่ง ห่วงโซ่แห่งคุณค่า ไปจนถึงจุดที่มีการใช้งานหรือลูกค้า คือความหมายของข้อใด\r\n', '', 'ห่วงโซ่อุปาน\r\n', '', 'โลจิสติกส์\r\n', '', 'การจัดการด้านส่งออกและนำเข้า\r\n', '', 'การจัดการขนส่ง', 2, 1, '4214'),
(1002, '', 'จุดวาบไฟและจุดติดไฟต่ำจะมีผลต่อเครื่องยนต์ในกรณีใดมากที่สุด', '', 'ช่วยให้เครื่องยนต์มีอัตราเร็วสูง', '', 'ช่วยให้เครื่องยนต์ติดได้ง่าย', '', 'ช่วยให้เครื่องยนต์มีอัตราการน๊อคต่ำ', '', 'ช่วยให้เครื่องยนต์มีแรงม้าสูงขึ้น', 4, 1, '30143'),
(1003, '', 'ข้อใดแสดงถึงความสามารถในการติดไฟ', '', 'การกระจายเป็นละอองเมื่อติดไฟ', '', 'เครื่องยนต์สตาร์ทติดเร็วขณะอุณหภูมิต่ำ', '', 'น้ำมันสามารถระเหยได้ง่ายแล้วติดไฟ', '', 'การเป็นไอได้เร็วและติดไฟง่าย', 1, 1, '30143'),
(1004, '', 'การทดสอบหาค่าความร้อนเชื้อเพลิงจะได้ค่าความร้อนเชื้อเพลิงขั้นสูงเมื่อสภาพการทดสอบเป็นอย่างไร\r\n', '', 'ผลต่างระหว่างอุณหภูมิห้องกับอุณหภูมิหลังการทดสอบสูงมาก', '', 'ไอน้ำจากการทดสอบกลั่นตัวเป็นหยดน้ำทั้งหมด', '', 'มวลเชื้อเพลิงสันดาปทั้งหมด', '', 'ความดันจากการสันดาปสูงกว่าความดันจากบรรยากาศมาก', 3, 1, '30143'),
(1005, '', 'ค่าความร้อนของเชื้อเพลิงมีประโยชน์อย่างไร', '', 'ทำให้เลือกใช้เชื้อเพลิงได้อย่างถูกต้อง', '', 'ทำให้แบ่งประเภทของเชื้อเพลิงได้', '', 'ทำให้เก็บรักษาเชื้อเพลิงได้ถูกต้อง', '', 'ทำให้ประหยัดเงินซื้อเชื้อเพลิง', 4, 1, '30143'),
(1006, '', 'การทดสอบความหนืดน้ำมันหล่อลื่นโดยใช้ Saybolt  Viscometer มีวิธีการทดสอบออย่างไร\r\n', '', 'หาน้ำหนักของน้ำมันที่ไหลผ่านท่อความฝืด', '', 'วัดปริมาณน้ำมันที่ไหลผ่านรูเล็ก ๆ ขนาดต่าง ๆ', '', 'จับเวลาการไหลของน้ำมันจำนวนหนึ่งที่ไหลผ่านรูเล็ก ๆ', '', 'หาความแตกต่างของอุณหภูมิเมื่อความหนืดเปลี่ยนแปลง', 2, 1, '30143'),
(1007, '', 'ความดันที่ปรากฏบนเกจวัดความดันคือข้อใด', '', 'ความดันที่เท่ากับความดันบรรยากาศ', '', 'ความดันที่สูงกว่าความดันบรรยากาศ', '', 'ความดันที่ต่ำกว่าความดันบรรยากาศ', '', 'ความดันที่เท่ากับความดันสมบูรณ์', 1, 1, '30143'),
