(1027, '', 'ตัวเลขที่แสดงบนสัญลักษณ์ของวาล์ว หมายเลขเลขใดแสดงถึงรูต่อเข้าวาล์วควบคุมเพื่อให้วาล์วทำงาน ?', '', '1', '', '2', '', '3', '', '12', 4, 1, '30143'),
(1028, '', 'ตัวอักษรที่แสดงบนสัญลักษณ์ของวาล์ว ตัวอักษรใดแสดงถึงรูระบายลมทิ้ง ?', '', 'P', '', 'A', '', 'Y', '', 'S', 4, 1, '30143'),
(1029, '', 'ตัวอักษรที่แสดงบนสัญลักษณ์ของวาล์ว ตัวอักษรใดแสดงถึงรูต่อลมเข้าวาล์ว ?\r\n', '', 'P', '', 'A', '', 'Y', '', 'D', 1, 1, '30143'),
(1030, '', 'ระบบไฮดรอลิกส์ในเครื่องจักรกลมีข้อดีอย่างไร', '', 'อุปกรณ์มีความละเอียดสูง  ', '', 'อุปกรณ์ทำงานมีการเคลื่อนที่ช้า', '', 'การตรวจซ่อมระบบสามารถทำได้ง่าย', '', 'สามารถควบคุมแรงและความเร็วให้เป็นอิสระต่อกันได้  ', 4, 1, '30143'),
(1031, '', 'วาล์วชนิดใดควบคุมความดันสูงสุดในการใช้งานของระบบไฮดรอลิกส์ ?\r\n', '', 'Pressure High Valve', '', 'Pressure Compensate Valve', '', 'Pressure Sequence Valve', '', 'Pressure Relief Valve', 4, 1, '30143'),
(1032, '', 'อุปกรณ์ใดเป็นส่วนประกอบของชุดต้นกำลังไฮดรอลิกส์ ?\r\n', '', 'วาล์วควบคุมทิศทาง', '', 'กระบอกสูบ', '', 'ออยล์คูลเลอร์', '', 'ถังพักน้ำมัน', 4, 1, '30143'),
(1033, '', 'ระบบไฮดรอลิกส์มีความหมายตรงกับข้อใด  ?\r\n', '', 'การเปลี่ยนแปลงกำลังงานของของไหลให้เป็นพลังงานกล  ', '', 'การเปลี่ยนแปลงพลังงานกลให้เป็นกำลังงานของของไหล', '', 'ระบบการส่งถ่ายกำลังงานโดยใช้ของไหลเป็นตัวกลาง', '', 'ระบบต้นกำลังของเครื่องจักรโดยใช้ของไหลในการสร้างกำลังงาน  ', 3, 1, '30143'),
(1034, '', 'ในระบบฉีดเชื้อเพลิงแบบ D-Jetronic ใช้ตัวตรวจจับใดเป็นสัญญาณหลัก\r\n', '', 'ตัวตรวจจับอุณหภูมิน้ำ', '', 'ตัวตรวจจับสุญญากาศ', '', 'ตัวตรวจจับตำแหน่งลิ้นเร่ง', '', 'ตัวตรวจจับอุณหภูมิอากาศ', 2, 1, '30143'),
(1035, '', 'ในการทดสอบการรั่วของหัวฉีด ถ้าการหยดของน้ำมันมากกว่า 1 หยดต่อนาที จะมีผลอย่างไรกับเครื่องยนต์', '', 'เครื่องยนต์สตาร์ทไม่ติด', '', 'เครื่องยนต์เร่งไม่ขึ้น', '', 'เครื่องยนต์สตาร์ทติดยาก', '', 'เครื่องยนต์ไม่มีกำลัง', 3, 1, '30143'),
(1036, '', 'สาเหตุใดที่ทำให้เกจวัดน้ำมันเชื้อเพลิงขึ้นค้างคงที่\r\n', '', 'ขดลวดชุดลูกลอยลัดวงจร', '', 'ชุดสายไฟขาด', '', 'ขดลวดชุดเกจวัดขาด', '', 'ขดลวดชุดลูกลอยขาด', 1, 1, '30143'),
(1037, '', 'การตรวจสอบการทำงานของหัวฉีดจะใช้แรงเคลื่อนไฟฟ้าประมาณเท่าไร\r\n', '', '6 โวลต์', '', '3 โวลต์', '', '12 โวลต์', '', '5 โวลต์', 3, 1, '30143'),
(1038, '', 'หัวฉีดของระบบ EFI จะทำการฉีดน้ำมันเชื้อเพลิงเมื่อใด\r\n', '', 'มีสัญญาณไฟฟ้าจากสวิทช์จุดระเบิดป้อนเข้าหัวฉีด', '', 'มีสัญญาณไฟฟ้าจากกล่อง ECU ครบวงจรที่หัวฉีด', '', 'มีสัญญาณไฟฟ้าจากตัวตรวจรับสัญญาณป้อนเข้าหัวฉีด', '', 'ความดันของน้ำมันเชื้อเพลิงในระบบสูงถึงค่าที่กำหนด', 2, 1, '30143'),
(1039, '', 'ข้อมูลความผิดปกติในหน่วยความจำของ ECUถูกลบออกโดยวิธีใด\r\n', '', 'ปิดสวิตช์กุญแจ', '', 'ถอดขั้วแบตเตอรี่', '', 'ถอดสายไฟที่ขั้ว + B ออก', '', 'ถอดสายไฟที่ขั้ว + B1ออก', 2, 1, '30143'),
(1040, '', 'เทอร์มิสเตอร์ ในวงจรเกจวัดอุณหภูมิน้ำ จะมีคุณสมบัติอย่างไร\r\n', '', 'เมื่ออุณหภูมิต่ำ จะมีความต้านทานคงที่', '', 'เมื่ออุณหภูมิต่ำ จะมีความต้านทานต่ำ', '', 'เมื่ออุณหภูมิสูง จะมีความต้านทานสูง', '', 'เมื่ออุณหภูมิต่ำ จะมีความต้านทานสูง', 4, 1, '30143'),
(1041, '', 'ก่อนทำการประกอบ โอริง หัวฉีด จะต้องหล่อลื่นด้วยอะไร\r\n', '', 'น้ำมันเกียร์', '', 'จาระบี ', '', 'น้ำมันเบรค', '', 'น้ำมันเบนซิน', 4, 1, '30143'),
(1042, '', 'การปรับแต่งความเร็วรอบเดินเบาของเครื่องยนต์ ที่อุณหภูมิทำงานควรมีความเร็วรอบประมาณเท่าใด\r\n', '', '400 รอบ/นาที', '', '600 รอบ/นาที', '', '800 รอบ/นาที', '', '1,000 รอบ/นาที', 3, 1, '30143'),
(1043, '', 'ขั้วสายไฟของตัวตรวจจับอุณหภูมิน้ำถูกปลดออกขณะเครื่องยนต์มีอุณหภูมิต่ำ เครื่องยนต์จะมีอาการอย่างไร\r\n', '', 'เครื่องยนต์จะสตาร์ทติดยากและสั่น', '', 'เครื่องยนต์สตาร์ทไม่ติด ', '', 'เครื่องยนต์ไม่มีกำลัง', '', 'เครื่องยนต์เร่งไม่ขึ้น', 1, 1, '30143');
